import java.util.Scanner;

public class Main{

	public static void main(String args[]){

		// Create a Scanner object to read input from the console
		Scanner sc = new Scanner(System.in);

		// Read five integers from the user input
		int a = sc.nextInt(); // Cost of item A
		int b = sc.nextInt(); // Cost of item B
		int c = sc.nextInt(); // Cost of item C
		int x = sc.nextInt(); // Quantity of item A needed
		int y = sc.nextInt(); // Quantity of item B needed

		// Variable to store the larger of x and y
		int big = 0;

		// Determine which quantity is larger, x or y
		if(x >= y) {
			big = x;
		}else {
			big = y;
		}

		// Calculate the absolute difference between x and y
		int abs = Math.abs(x - y);

		// Variable to store the total cost
		int sum = 0;

		// Check if the combined cost of A and B is greater than or equal to twice the cost of C
		if(a + b >= 2 * c) {
			// Calculate the cost for the minimum quantity of x or y using 2 * c
			sum = (big - abs) * (2 * c);

			// Calculate the remaining cost based on which quantity is larger
			if(big == x && a >= (2 * c)) {
				sum += (abs * (2 * c));
			}else if(big == x && a < (2 * c)) {
				sum += (abs * a);
			}else if(big == y && b >= (2 * c)) {
				sum += (abs * (2 * c));
			}else if(big == y && b < (2 * c)) {
				sum += (abs * b);
			}
		}else {
			// Calculate the cost for the minimum quantity of x or y using a + b
			sum = (big - abs) * (a + b);

			// Calculate the remaining cost based on which quantity is larger
			if(big == x && a >= (2 * c)) {
				sum += (abs * (2 * c));
			}else if(big == x && a < (2 * c)) {
				sum += (abs * a);
			}else if(big == y && b >= (2 * c)) {
				sum += (abs * (2 * c));
			}else if(big == y && b < (2 * c)) {
				sum += (abs * b);
			}
		}

		// Output the total cost
		System.out.println(sum);
	}
}

